(function(){
  function send(name,params){if(typeof window.gtag==='function'){window.gtag('event',name,params||{});}}
  function pathType(path){if(path.indexOf('/outfits/')===0)return 'outfit';if(path.indexOf('/style/')===0)return 'style';if(path.indexOf('/blog/')===0)return 'article';if(path.indexOf('/closet')===0)return 'closet';return 'internal';}
  document.addEventListener('click',function(e){var a=e.target.closest&&e.target.closest('a[href]');if(!a)return;try{var u=new URL(a.href,location.href);if(u.origin!==location.origin)return;var type=pathType(u.pathname);if(type==='outfit')send('click_outfit',{link_url:u.pathname,link_text:(a.textContent||'').trim().slice(0,100)});else if(type==='closet')send('click_closet',{link_url:u.pathname});else if(type==='article')send('click_related_article',{link_url:u.pathname,link_text:(a.textContent||'').trim().slice(0,100)});}catch(err){}});
  var fired50=false,fired90=false;function scrollDepth(){var d=document.documentElement;var max=Math.max(1,d.scrollHeight-innerHeight);var pct=Math.round((scrollY/max)*100);if(pct>=50&&!fired50){fired50=true;send('article_scroll_50',{page_path:location.pathname});}if(pct>=90&&!fired90){fired90=true;send('article_scroll_90',{page_path:location.pathname});}}
  if(location.pathname.indexOf('/blog/')===0){addEventListener('scroll',scrollDepth,{passive:true});scrollDepth();}
})();
